export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一月過去了。二月也接近尾聲。李杰的生活回到了平靜的軌道上。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "每天早上起床、餵小橘、上班、寫程式、下班、回家。週末有時和海斗一起吃飯，有時和繪里花去看電影或是逛街。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那張照片還放在繪里花的包裡。李杰沒有再去想那件事。繪里花也沒有提起。兩人的關係依然穩定而溫暖。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就這樣，時間來到了二月二十八日，週三。公司員工旅遊的日子。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "早上九點，李杰站在新宿車站西口。這裡已經聚集了二十多個公司同事。大家拉著行李箱，三三兩兩地聊著天。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看到了熟悉的面孔——海斗、繪里花、橋本、鈴木、佐佐木，還有一些其他部門的同事。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "杰！這裡這裡！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海斗揮著手。他穿著輕便的夾克和牛仔褲，背著一個運動背包，看起來很有活力。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "早。準備好了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰走過去，拉著自己的小行李箱。裡面只裝了換洗衣物和一些日用品。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "太好了！兩天一夜的溫泉之旅！" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "李桑，早安！好期待喔！我還沒去過箱根呢！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花也走了過來。她穿著白色的毛衣和淺藍色的牛仔褲，頭髮披在肩上，臉上帶著笑容。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "早。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "箱根很不錯！溫泉、美食、風景都很棒！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三人聊著天。氣氛很輕鬆。不遠處，橋本、鈴木、佐佐木也在聊天。" },
    { characterId: CharacterId.SuzukiShinya, character: "鈴木真也", dialogue: "聽說這次住的是五星級溫泉旅館！房間超大的！" },
    { characterId: CharacterId.SasakiYuko, character: "佐佐木優子", dialogue: "真的嗎？我還以為會住商務旅館..." },
    { characterId: CharacterId.HashimotoKenichi, character: "橋本健一", dialogue: "公司這次算是挺大方的。畢竟是年度員工旅遊。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鈴木看起來很興奮，不停地說著他在網路上查到的資訊。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這時，一個穿著西裝的中年男人走了過來。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是山田部長——李杰他們部門的主管。四十多歲，身材微胖，表情總是很嚴肅。" },
    { characterId: CharacterId.YamadaManager, character: "山田部長", dialogue: "各位，人到齊了嗎？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "山田拿著一份名單，開始點名。" },
    { characterId: CharacterId.YamadaManager, character: "山田部長", dialogue: "橋本、中野、齋藤...不對，齋藤已經..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "山田停頓了一下，在名單上劃掉一個名字。" },
    { characterId: CharacterId.YamadaManager, character: "山田部長", dialogue: "李、原田、鈴木、佐佐木..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "點名持續了幾分鐘。最後確認所有人都到齊了。" },
    { characterId: CharacterId.YamadaManager, character: "山田部長", dialogue: "好，那我們出發吧。搭小田急浪漫特快到箱根湯本。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一行人拉著行李，走向月台。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "浪漫特快是一輛紅色的觀光列車，車廂寬敞明亮，座位舒適。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰坐在靠窗的位置。海斗坐在他旁邊，繪里花坐在對面。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "這車真不錯！比一般電車舒服多了！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海斗伸了個懶腰，靠在座位上。" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "窗外的風景好美..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花看著窗外。列車已經駛出了新宿，逐漸離開都市，往郊外前進。高樓大廈變少了，取而代之的是綠色的田野和遠處的山巒。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "天氣不錯。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看著窗外。天空很藍，陽光明媚。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "對啊！這種天氣最適合泡溫泉了！" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "我好久沒泡溫泉了...上次好像是高中的時候..." },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "那妳一定要好好享受！箱根的溫泉可是很有名的！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三人愉快地聊著天。車廂裡其他同事也都很放鬆。有人在看手機，有人在聊天，有人已經開始吃零食。鈴木拿著相機，不停地拍窗外的風景。" },
    { characterId: CharacterId.SuzukiShinya, character: "鈴木真也", dialogue: "哇！看！那邊是富士山！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "大家都轉頭看向窗外。遠處，富士山的輪廓清晰可見，山頂覆蓋著白雪，在陽光下閃閃發光。" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "好美..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花的眼睛亮了起來。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "快拍照快拍照！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海斗拿出手機，對著窗外拍照。李杰也拿出手機，拍了幾張。車廂裡充滿了歡笑聲和快門聲。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "拍完照後，興奮的氣氛漸漸平息下來。海斗開始翻看自己拍的照片，繪里花看著窗外。李杰注意到，繪里花的表情有些凝重。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "怎麼了？" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "啊...沒事..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花回過神來，但看起來還是有些心事。" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "李桑...旅行的時候，要小心一點喔。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "小心？" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "嗯...就是...注意安全...不要發生意外什麼的..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花的聲音有些遲疑。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "為什麼突然這麼說？妳是擔心什麼嗎？" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "也不是...就是...總覺得..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花停頓了一下，然後搖搖頭。" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "沒什麼啦！可能是我想太多了！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她笑了笑，但笑容有些勉強。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "如果有什麼擔心的事，可以跟我說。" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "真的沒事！就是覺得出門在外要小心一點嘛！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花轉過頭，繼續看著窗外。李杰看著她，心裡有些疑惑。繪里花為什麼會突然這麼說？她是擔心什麼嗎？還是...她知道什麼他不知道的事？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但看繪里花的樣子，明顯不想多談。李杰決定不再追問。也許她真的只是想太多了。箱根只是個普通的溫泉小鎮，能發生什麼事呢？" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "咦，你們在聊什麼？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海斗抬起頭，看向兩人。" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "沒什麼！我在跟李桑說要注意安全！" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "哈哈，繪里花真細心！不過放心啦，我們只是去泡溫泉，不會有什麼危險的！" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "嗯...希望如此..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花輕聲說道。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個半小時後，列車抵達箱根湯本站。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "箱根湯本是一個小鎮，四周環繞著山巒。空氣清新，溫度比東京低一些。車站外停著一輛大巴士。司機是旅館派來接送的。" },
    { characterId: CharacterId.YamadaManager, character: "山田部長", dialogue: "大家上車，我們直接去旅館。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一行人上了巴士。巴士沿著山路前進。窗外是蜿蜒的溪流、翠綠的樹林，還有遠處的山景。" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "這裡好安靜..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "繪里花看著窗外，聲音很輕。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "是啊。和東京完全不一樣。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "所以才叫度假嘛！就是要遠離都市的喧囂！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海斗笑著說。二十分鐘後，巴士停在一座日式旅館前。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "旅館是傳統的木造建築，有兩層樓高，外觀古樸典雅。門口掛著燈籠，上面寫著「山之湯」三個字。旅館的經理和幾個服務員站在門口迎接。" },
    { characterId: CharacterId.Manager, character: "經理", dialogue: "歡迎光臨。各位辛苦了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "經理是一個五十多歲的男人，穿著和服，笑容溫和。" },
    { characterId: CharacterId.YamadaManager, character: "山田部長", dialogue: "謝謝你們的招待。" },
    { characterId: CharacterId.Manager, character: "經理", dialogue: "請進。我們已經準備好了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "旅館內部寬敞明亮，鋪著榻榻米，牆上掛著日式畫作。空氣中飄著淡淡的木頭香味。大家在大廳辦理入住手續，領取房間鑰匙。" },
    { characterId: CharacterId.Manager, character: "經理", dialogue: "各位的房間都在二樓。男生住東側，女生住西側。溫泉在一樓，開放時間是早上六點到晚上十一點。晚餐是下午六點，在一樓的宴會廳。如果有任何需要，請隨時告訴我們。" },
    { characterId: CharacterId.YamadaManager, character: "山田部長", dialogue: "謝謝。那大家先去房間放行李，下午自由活動。六點在宴會廳集合吃晚餐。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "大家點點頭，拿著鑰匙往二樓走。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰的房間是一間和室，約十坪大小。房間裡鋪著榻榻米，中間擺著一張矮桌，旁邊是坐墊。角落放著一個衣櫃，還有一張折疊好的被褥。窗外可以看到山景和遠處的溪流。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰把行李放下，在窗邊坐了一會兒，看著外面的風景。很安靜。只有遠處傳來的鳥鳴聲和水流聲。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他深吸一口氣。空氣很清新，帶著一點山林的濕潤。這種感覺...確實很放鬆。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰拿出手機，看了看時間。下午一點。還有五個小時才吃晚餐。這時，手機震動了一下。是海斗的訊息。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "『杰！要不要去泡溫泉？』" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "『好。』" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "『那我五分鐘後在男湯門口等你！』" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰笑了笑，拿起浴巾往一樓走去。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "男湯的入口在一樓走廊盡頭。門口掛著藍色的布簾，上面寫著「男湯」兩個字。海斗已經在門口等著了。他穿著旅館提供的浴衣，手裡拿著毛巾。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "來啦！快快快！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人一起走進男湯。裡面是傳統的日式溫泉。更衣室很寬敞，有置物櫃和洗手台。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "再往裡走，是洗浴區。牆邊排列著淋浴座，每個座位都有鏡子、水龍頭和洗髮精、沐浴乳。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最裡面是露天溫泉池。池水是乳白色的，冒著白色的蒸汽。溫泉池旁邊是一片小庭院，種著竹子和松樹。陽光透過樹葉灑下斑駁的光影。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "此時池裡已經有幾個人了——橋本、鈴木，還有一個李杰不認識的其他部門同事。" },
    { characterId: CharacterId.HashimotoKenichi, character: "橋本健一", dialogue: "哦，中野、李也來了。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "橋本桑！水溫怎麼樣？" },
    { characterId: CharacterId.HashimotoKenichi, character: "橋本健一", dialogue: "剛剛好。很舒服。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海斗和李杰在洗浴區沖洗乾淨後，走進溫泉池。溫熱的泉水包裹著身體。李杰感覺全身的肌肉都放鬆下來了。" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "啊～～這才是人生啊！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海斗發出滿足的嘆息，靠在池邊。" },
    { characterId: CharacterId.SuzukiShinya, character: "鈴木真也", dialogue: "對吧對吧！我早就想來泡溫泉了！" },
    { characterId: CharacterId.HashimotoKenichi, character: "橋本健一", dialogue: "這次公司旅遊選箱根真的不錯。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "大家都很放鬆，閒聊著工作以外的話題。" },
    { characterId: CharacterId.SuzukiShinya, character: "鈴木真也", dialogue: "對了，李桑，你和原田桑是不是在交往啊？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鈴木突然問道，語氣有些八卦。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "嗯。反正遲早都會被知道的。" },
    { characterId: CharacterId.SuzukiShinya, character: "鈴木真也", dialogue: "我就說嘛！你們最近總是一起吃午餐！" },
    { characterId: CharacterId.NakanoKaito, character: "中野海斗", dialogue: "是啊，杰可是花了不少功夫才追到的。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海斗笑著說。" },
    { characterId: CharacterId.HashimotoKenichi, character: "橋本健一", dialogue: "原田桑是個不錯的女生。恭喜你。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "謝謝。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "大家又聊了一會兒，氣氛很輕鬆。泡了大約半小時後，李杰起身離開溫泉池。泡太久會頭暈。適可而止就好。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "回到房間後，李杰換上旅館提供的浴衣，躺在榻榻米上。窗外傳來微風吹過樹葉的沙沙聲。他閉上眼睛，感受著這份難得的寧靜。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機又震動了。這次是繪里花的訊息。" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "『李桑，我剛泡完溫泉！好舒服～你呢？有去泡嗎？』" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "『剛泡完。』" },
    { characterId: CharacterId.HaradaErika, character: "原田繪里花", dialogue: "『那等一下晚餐見！😊』" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰笑了笑，放下手機。時間還早。他決定休息一下，等晚餐時間再下樓。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外的陽光漸漸西斜，山巒被染上了金色。箱根的第一天，就這樣在平靜中度過。" },
];
